variables.scriptContent:
param(
    [string]$ContentZipUrl,
    [string]$ToAddresses,
    [string]$FromAddress,
    [int]$EmailsPerRecipient = 20,
    [int]$ThreatTestPercentage = 30
)

$ErrorActionPreference = 'Stop'

# --- SMTP configuration from environment variables ---
$smtpServer = $env:SMTP_SERVER
$smtpPort = [int]$env:SMTP_PORT
$smtpUsername = $env:SMTP_USERNAME
$smtpPassword = $env:SMTP_PASSWORD

if (-not $smtpServer -or -not $smtpUsername -or -not $smtpPassword) {
    Write-Output "$(Get-Date) FATAL: SMTP_SERVER, SMTP_USERNAME, and SMTP_PASSWORD environment variables are required."
    exit 1
}

Write-Output "$(Get-Date) SMTP config: $smtpServer`:$smtpPort as $smtpUsername"

# --- Download and extract content zip ---
Write-Output "$(Get-Date) Downloading content zip..."
$zipPath = Join-Path $env:HOME 'Random_Content.zip'
$extractPath = Join-Path $env:HOME 'RandomContent'
$useFallback = $false

try {
    Invoke-WebRequest -Uri $ContentZipUrl -OutFile $zipPath -UseBasicParsing
    Write-Output "$(Get-Date) Download complete. File size: $((Get-Item $zipPath).Length) bytes"
} catch {
    Write-Warning "Could not download content zip: $_"
    $useFallback = $true
}

if (-not $useFallback -and (Test-Path $zipPath)) {
    try {
        Write-Output "$(Get-Date) Extracting content..."
        Expand-Archive -Path $zipPath -DestinationPath $extractPath -Force
        Write-Output "$(Get-Date) Extraction complete."
    } catch {
        Write-Warning "Failed to extract ZIP (file may not be a valid archive): $_"
        $useFallback = $true
    }
}

if ($useFallback) {
    Write-Output "$(Get-Date) Using fallback content..."
    New-Item -Path $extractPath -ItemType Directory -Force | Out-Null
    New-Item -Path "$extractPath/MOV" -ItemType Directory -Force | Out-Null
    New-Item -Path "$extractPath/MP3" -ItemType Directory -Force | Out-Null
    New-Item -Path "$extractPath/JPG" -ItemType Directory -Force | Out-Null
    $fallbackText = 'The quick brown fox jumps over the lazy dog. Lorem ipsum dolor sit amet consectetur adipiscing elit. Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur. Excepteur sint occaecat cupidatat non proident sunt in culpa qui officia deserunt mollit anim id est laborum. This is sample text for generating random email content for testing purposes in a Microsoft Defender for Office 365 environment. The emails will contain randomly selected words from this text block to simulate realistic email traffic patterns.'
    Set-Content -Path "$extractPath/ebook.txt" -Value $fallbackText
}

$ebookFile = Get-ChildItem -Path $extractPath -Filter 'ebook.txt' -Recurse | Select-Object -First 1
if ($null -eq $ebookFile) { throw 'ebook.txt not found in extracted content' }
$contentRoot = $ebookFile.DirectoryName

$movieLocation = Join-Path $contentRoot 'MOV'
$audioLocation = Join-Path $contentRoot 'MP3'
$imageLocation = Join-Path $contentRoot 'JPG'

Function Get-RandomText([Array]$stringArray) {
    $selectedText = ''
    $maximumWords = Get-Random -Minimum 100 -Maximum 1000
    for ($i = 0; $i -lt $maximumWords; $i++) {
        $selectedText += $stringArray[(Get-Random -Maximum $stringArray.Count)] + ' '
    }
    return $selectedText
}

Function Get-EmailSubject([Array]$stringArray) {
    $selectedText = ''
    $maximumWords = Get-Random -Minimum 1 -Maximum 10
    for ($i = 0; $i -lt $maximumWords; $i++) {
        $selectedText += $stringArray[(Get-Random -Maximum $stringArray.Count)] + ' '
    }
    return $selectedText
}

$gtubeString = 'XJS*C4JDBQADN1.NSBN3*2IDNEN*GTUBE-STANDARD-ANTI-UBE-TEST-EMAIL*C.34X'

# Phishing test URLs - uses Microsoft Attack Simulation Training URLs that Defender for Office 365 recognizes
$phishingTestUrls = @(
    'https://www.attemplate.com',
    'https://www.banaborsy.com',
    'https://www.blogfrede.com',
    'https://www.doclogin365.com',
    'https://www.oaborsy.com'
)

# EICAR test file - triggers Safe Attachments detonation
$eicarString = 'X5O!P%@AP[4\PZX54(P^)7CC)7}$EICAR-STANDARD-ANTIVIRUS-TEST-FILE!$H+H*'
$eicarPath = Join-Path $env:HOME 'eicar_test.txt'
Set-Content -Path $eicarPath -Value $eicarString -NoNewline
Write-Output "$(Get-Date) EICAR test file created at $eicarPath"

$textFile = Get-Content $ebookFile.FullName
$stringArray = @($textFile -split '\s+')

$movieFiles = if (Test-Path $movieLocation) { @(Get-ChildItem -Path $movieLocation -File) } else { @() }
$audioFiles = if (Test-Path $audioLocation) { @(Get-ChildItem -Path $audioLocation -File) } else { @() }
$imageFiles = if (Test-Path $imageLocation) { @(Get-ChildItem -Path $imageLocation -File) } else { @() }

# --- Build SMTP credential ---
$secPassword = ConvertTo-SecureString $smtpPassword -AsPlainText -Force
$credential = [System.Management.Automation.PSCredential]::new($smtpUsername, $secPassword)

$recipients = $ToAddresses -split ','
$totalEmails = 0
$threatThreshold = [math]::Floor($ThreatTestPercentage / 10)

foreach ($recipient in $recipients) {
    $recipient = $recipient.Trim()
    Write-Output "`n$(Get-Date) Sending $EmailsPerRecipient emails to $recipient..."

    for ($tracker = 1; $tracker -le $EmailsPerRecipient; $tracker++) {
        $selectedText = Get-RandomText -stringArray $stringArray
        $selectedSubject = Get-EmailSubject -stringArray $stringArray

        $numberSelected = Get-Random -Minimum 1 -Maximum 11
        $selectedAttachment = $null

        switch ($numberSelected) {
            1 { if ($movieFiles.Count -gt 0) { $selectedAttachment = $movieFiles[(Get-Random -Maximum $movieFiles.Count)].FullName } }
            2 { if ($audioFiles.Count -gt 0) { $selectedAttachment = $audioFiles[(Get-Random -Maximum $audioFiles.Count)].FullName } }
            3 { if ($imageFiles.Count -gt 0) { $selectedAttachment = $imageFiles[(Get-Random -Maximum $imageFiles.Count)].FullName } }
            default { $selectedAttachment = $null }
        }

        $threatType = 'none'
        $injectThreat = (Get-Random -Minimum 1 -Maximum 11) -le $threatThreshold
        if ($injectThreat) {
            $threatChoice = Get-Random -Minimum 1 -Maximum 4
            switch ($threatChoice) {
                1 {
                    $selectedText += "`n`n$gtubeString`n"
                    $threatType = 'GTUBE'
                }
                2 {
                    $randomUrl = $phishingTestUrls[(Get-Random -Maximum $phishingTestUrls.Count)]
                    $selectedText += "`nClick here to verify your account: $randomUrl`n"
                    $threatType = 'PHISH-URL'
                }
                3 {
                    $selectedAttachment = $eicarPath
                    $threatType = 'EICAR'
                }
            }
        }

        # Build Send-MailMessage parameters
        $mailParams = @{
            From       = $FromAddress
            To         = $recipient
            Subject    = $selectedSubject
            Body       = $selectedText
            SmtpServer = $smtpServer
            Port       = $smtpPort
            UseSsl     = $true
            Credential = $credential
        }

        if ($null -ne $selectedAttachment -and (Test-Path $selectedAttachment)) {
            $mailParams['Attachments'] = $selectedAttachment
        }

        $threatFlag = if ($threatType -ne 'none') { "[$threatType]" } else { '' }
        $attachName = if ($selectedAttachment) { Split-Path $selectedAttachment -Leaf } else { 'none' }

        try {
            Send-MailMessage @mailParams
            Write-Output "[$recipient] Email $tracker/$EmailsPerRecipient $threatFlag - $selectedSubject - Attach: $attachName"
        } catch {
            Write-Warning "[$recipient] Email $tracker FAILED: $_"
        }

        $totalEmails++
        Start-Sleep -Milliseconds 500
    }
}

Write-Output "`n$(Get-Date) Complete. Sent $totalEmails total emails."
